/// Try to simplify a switch on the result of a ucmp/scmp intrinsic.
/// The ucmp/scmp intrinsics return -1, 0, or 1 depending on whether
/// the first operand is less than, equal to, or greater than the second.
/// This function converts such switches into appropriate icmp + branch.
static bool simplifySwitchOnCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder) {
  Value *Cond = SI->getCondition();

  // Check if the condition is a ucmp or scmp intrinsic
  auto *II = dyn_cast<IntrinsicInst>(Cond);
  if (!II)
    return false;

  Intrinsic::ID ID = II->getIntrinsicID();
  if (ID != Intrinsic::ucmp && ID != Intrinsic::scmp)
    return false;

  // Get the operands of the cmp intrinsic
  Value *Op0 = II->getOperand(0);
  Value *Op1 = II->getOperand(1);

  // We need exactly two destinations (cases can be grouped)
  // Collect which case values go to which destination
  SmallDenseMap<BasicBlock *, SmallVector<int64_t, 4>> DestCases;

  for (const auto &Case : SI->cases()) {
    BasicBlock *Dest = Case.getCaseSuccessor();
    int64_t Val = Case.getCaseValue()->getSExtValue();
    DestCases[Dest].push_back(Val);
  }

  // Also consider the default destination with "no specific value"
  BasicBlock *DefaultDest = SI->getDefaultDest();
  bool HasUnreachableDefault = isa<UnreachableInst>(DefaultDest->getFirstNonPHIOrDbg());

  // Count distinct destinations (excluding unreachable default)
  SmallVector<BasicBlock *, 4> Dests;
  for (auto &Pair : DestCases) {
    if (!(HasUnreachableDefault && Pair.first == DefaultDest))
      Dests.push_back(Pair.first);
  }
  if (!HasUnreachableDefault)
    Dests.push_back(DefaultDest);

  // Remove duplicates
  llvm::sort(Dests);
  Dests.erase(std::unique(Dests.begin(), Dests.end()), Dests.end());

  // We need exactly 2 destinations to convert to a branch
  if (Dests.size() != 2)
    return false;

  BasicBlock *DestA = Dests[0];
  BasicBlock *DestB = Dests[1];

  // Determine which values go to each destination
  SmallVector<int64_t, 4> ValuesA, ValuesB;

  for (auto &Pair : DestCases) {
    if (Pair.first == DestA) {
      ValuesA.append(Pair.second.begin(), Pair.second.end());
    } else if (Pair.first == DestB) {
      ValuesB.append(Pair.second.begin(), Pair.second.end());
    }
  }

  // If default is reachable and not in DestCases, it could match any remaining value
  if (!HasUnreachableDefault) {
    // Default covers all values not explicitly listed
    // For simplicity, we only handle cases where default goes to one of our two dests
    // and all explicit cases are accounted for
    // Since ucmp/scmp only returns -1, 0, or 1, check if we have all three
    SmallVector<int64_t, 4> AllExplicitValues;
    for (auto &Pair : DestCases) {
      AllExplicitValues.append(Pair.second.begin(), Pair.second.end());
    }
    llvm::sort(AllExplicitValues);

    // Check which of -1, 0, 1 are missing
    bool HasNegOne = llvm::binary_search(AllExplicitValues.begin(), AllExplicitValues.end(), -1LL);
    bool HasZero = llvm::binary_search(AllExplicitValues.begin(), AllExplicitValues.end(), 0LL);
    bool HasOne = llvm::binary_search(AllExplicitValues.begin(), AllExplicitValues.end(), 1LL);

    if (!HasNegOne)
      ValuesA.push_back(-1);  // Assume default goes to DestA (we'll verify below)
    if (!HasZero && !HasNegOne && !HasOne) {
      // Only default exists
      return false;  // Can't optimize a switch with only default
    }
  }

  // Sort values for easier analysis
  llvm::sort(ValuesA);
  llvm::sort(ValuesB);

  // Now determine the comparison predicate based on which values go where
  // Possible patterns for two-destination switches on cmp result:
  // 
  // For unsigned (ucmp):
  //   - Values {-1, 0} to one dest, {1} to other → ugt/ule
  //   - Values {-1} to one dest, {0, 1} to other → ult/uge  
  //   - Values {0} to one dest, {-1, 1} to other → une/ueq
  //   - Values {-1, 1} to one dest, {0} to other → une/ueq
  //
  // For signed (scmp), same logic applies

  ICmpInst::Predicate PredTrueToA = ICmpInst::BAD_ICMP_PREDICATE;
  ICmpInst::Predicate PredTrueToB = ICmpInst::BAD_ICMP_PREDICATE;
  bool IsUnsigned = (ID == Intrinsic::ucmp);

  // Helper lambda to check set equality
  auto setsEqual = [](const SmallVectorImpl<int64_t> &A, const SmallVectorImpl<int64_t> &B) {
    if (A.size() != B.size()) return false;
    for (size_t i = 0; i < A.size(); ++i)
      if (A[i] != B[i]) return false;
    return true;
  };

  SmallVector<int64_t> NegOne = {-1};
  SmallVector<int64_t> Zero = {0};
  SmallVector<int64_t> One = {1};
  SmallVector<int64_t> NegOneZero = {-1, 0};
  SmallVector<int64_t> NegOneOne = {-1, 1};
  SmallVector<int64_t> ZeroOne = {0, 1};
  SmallVector<int64_t> AllThree = {-1, 0, 1};

  // Check various patterns
  if (setsEqual(ValuesA, NegOneZero) && setsEqual(ValuesB, One)) {
    // A gets {-1, 0}, B gets {1}
    // Branch to B when Op0 > Op1
    PredTrueToB = IsUnsigned ? ICmpInst::ICMP_UGT : ICmpInst::ICMP_SGT;
    PredTrueToA = IsUnsigned ? ICmpInst::ICMP_ULE : ICmpInst::ICMP_SLE;
  } else if (setsEqual(ValuesA, One) && setsEqual(ValuesB, NegOneZero)) {
    // A gets {1}, B gets {-1, 0}
    PredTrueToA = IsUnsigned ? ICmpInst::ICMP_UGT : ICmpInst::ICMP_SGT;
    PredTrueToB = IsUnsigned ? ICmpInst::ICMP_ULE : ICmpInst::ICMP_SLE;
  } else if (setsEqual(ValuesA, NegOne) && setsEqual(ValuesB, ZeroOne)) {
    // A gets {-1}, B gets {0, 1}
    PredTrueToA = IsUnsigned ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_SLT;
    PredTrueToB = IsUnsigned ? ICmpInst::ICMP_UGE : ICmpInst::ICMP_SGE;
  } else if (setsEqual(ValuesA, ZeroOne) && setsEqual(ValuesB, NegOne)) {
    // A gets {0, 1}, B gets {-1}
    PredTrueToA = IsUnsigned ? ICmpInst::ICMP_UGE : ICmpInst::ICMP_SGE;
    PredTrueToB = IsUnsigned ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_SLT;
  } else if (setsEqual(ValuesA, Zero) && setsEqual(ValuesB, NegOneOne)) {
    // A gets {0}, B gets {-1, 1}
    PredTrueToA = ICmpInst::ICMP_EQ;
    PredTrueToB = ICmpInst::ICMP_NE;
  } else if (setsEqual(ValuesA, NegOneOne) && setsEqual(ValuesB, Zero)) {
    // A gets {-1, 1}, B gets {0}
    PredTrueToA = ICmpInst::ICMP_NE;
    PredTrueToB = ICmpInst::ICMP_EQ;
  } else if (setsEqual(ValuesA, AllThree) || setsEqual(ValuesB, AllThree)) {
    // All cases go to same destination - should have been simplified already
    return false;
  } else {
    // Unrecognized pattern
    return false;
  }

  // Create the comparison and branch
  Builder.SetInsertPoint(SI);
  Value *Cmp = Builder.CreateICmp(PredTrueToA, Op0, Op1, "cmp");
  BranchInst::Create(DestA, DestB, Cmp, SI);

  // Erase the old switch
  SI->eraseFromParent();

  return true;
}

